const fs = require('fs');
const path = require('path');

const SKIP = new Set(['node_modules', '.git', '.next']);

function walk(dir, root = dir) {
  const out = [];
  for (const f of fs.readdirSync(dir)) {
    if (SKIP.has(f)) continue;
    const full = path.join(dir, f);
    if (fs.statSync(full).isDirectory()) out.push(...walk(full, root));
    else if (full.endsWith('.md')) out.push({ path: path.relative(root, full), full });
  }
  return out;
}

const root = process.argv[2] || '.';
const files = walk(root);
const out = files.map(({ path: p, full }) =>
  `## ${p}\n\n${fs.readFileSync(full, 'utf8')}`
).join('\n\n---\n\n');
console.log(out);

import { readFileSync, readdirSync, statSync } from 'node:fs';
import { join, relative } from 'node:path';

const SKIP = new Set(['node_modules', '.git', '.next']);

interface MdFile {
  path: string;
  full: string;
}

function walk(dir: string, root: string = dir): MdFile[] {
  const out: MdFile[] = [];
  for (const f of readdirSync(dir)) {
    if (SKIP.has(f)) continue;
    const full = join(dir, f);
    if (statSync(full).isDirectory()) out.push(...walk(full, root));
    else if (full.endsWith('.md')) out.push({ path: relative(root, full), full });
  }
  return out;
}

const root = process.argv[2] ?? '.';
const files = walk(root);
const out = files
  .map(({ path, full }) => `## ${path}\n\n${readFileSync(full, 'utf8')}`)
  .join('\n\n---\n\n');
console.log(out);
